  state.realUser = ru;
  state.user = { id: (o.id != null ? o.id : ru.id), name: (o.name || ru.name), email: ru.email, role: o.role };
  state.viewAsId = (o.id != null && o.id !== ru.id) ? o.id : null;
  state.viewAs = o.label;
  state.sidebarSection = null;
