function escHtml(s) {
  if (s == null) return '';
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function copyToClipboard(text, btn) {
  navigator.clipboard.writeText(text).then(function() {
    if (btn) { var orig = btn.innerHTML; btn.innerHTML = '&#10003;'; btn.style.color = 'var(--success)'; setTimeout(function(){ btn.innerHTML = orig; btn.style.color = ''; }, 1200); }
  }).catch(function() {
    var ta = document.createElement('textarea'); ta.value = text; document.body.appendChild(ta); ta.select(); document.execCommand('copy'); document.body.removeChild(ta);
    if (btn) { var orig = btn.innerHTML; btn.innerHTML = '&#10003;'; btn.style.color = 'var(--success)'; setTimeout(function(){ btn.innerHTML = orig; btn.style.color = ''; }, 1200); }
  });
}

function formatDate(d) {
  if (!d) return '—';
  // Date-only values (Postgres DATE columns) arrive as 'YYYY-MM-DD' or midnight-UTC
  // ('YYYY-MM-DDT00:00:00.000Z'). Building a local Date from those shifts the calendar
  // day back one in negative-UTC timezones, so render such values from their parts.
  var m = (typeof d === 'string') && d.match(/^(\d{4})-(\d{2})-(\d{2})(?:T00:00:00(?:\.000)?Z)?$/);
  var dt = m ? new Date(parseInt(m[1], 10), parseInt(m[2], 10) - 1, parseInt(m[3], 10)) : new Date(d);
  return dt.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}
function formatDateTime(d) {
  if (!d) return '—';
  var dt = new Date(d);
  return dt.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) + ' ' + dt.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
}
function timeAgo(d) {
  if (!d) return null;
  var diff = Date.now() - new Date(d).getTime();
  if (diff < 0) diff = 0;
  var m = Math.floor(diff / 60000);
  if (m < 2) return 'now';
  if (m < 60) return m + 'm ago';
  var h = Math.floor(m / 60);
  if (h < 24) return h + 'h ago';
  var days = Math.floor(h / 24);
  if (days < 7) return days + 'd ago';
  return null;
}
function userActivityCell(u) {
  var ago = timeAgo(u.last_seen_at);
  if (ago === 'now') return '<span style="color:var(--success);font-size:13px;white-space:nowrap">&#9679; Active now</span>';
  if (ago) return '<span style="color:var(--text-muted-color);font-size:13px;white-space:nowrap">' + escHtml(ago) + '</span>';
  return '<span style="color:var(--text-muted-color);font-size:13px">' + (u.last_seen_at ? escHtml(formatDate(u.last_seen_at)) : '—') + '</span>';
}

function badgeHtml(status) {
  var cls = (status || '').replace(/\s+/g, '-');
  return '<span class="badge badge-' + escHtml(cls) + '">' + escHtml(status) + '</span>';
}

var EMPLOYEE_PERMS = ['view_pos','create_po','edit_po','delete_po','submit_po','view_quotes','create_quote','edit_quote','delete_quote','push_quote_po','view_vr','create_vr','edit_vr','delete_vr','submit_vr','view_deposits','create_deposit','delete_deposit','export_deposits','view_signoffs','create_signoff','edit_signoff','complete_signoff','delete_signoff','view_tasks','view_work_orders','view_schedule','view_invoices','create_invoice','edit_invoice','delete_invoice','view_signatures','view_timeclock','view_pto','view_ptt','ptt_direct'];
var PERM_DEFAULTS = {
  manager: ['view_users','manage_cities','manage_geico','manage_running','manage_vehicles','manage_vendors','manage_addresses','approve_vr','manage_tasks','manage_work_orders','manage_schedule','manage_parts','manage_invoice_setup','assign_reviews','view_feedback','manage_feedback','manage_signatures','manage_timeclock','manage_pto','ptt_all_channels','view_team_quiz','manage_onboarding'].concat(EMPLOYEE_PERMS),
  locksmith: EMPLOYEE_PERMS.slice(),
  locksmith_coordinator: EMPLOYEE_PERMS.concat(['manage_work_orders','ptt_all_channels']),
  dispatcher: EMPLOYEE_PERMS.concat(['manage_work_orders','ptt_all_channels']),
  roadside_technician: EMPLOYEE_PERMS.slice()
};
function roleLabel(r) {
  var m = { locksmith:'Locksmith', locksmith_coordinator:'Locksmith Coordinator', dispatcher:'Dispatcher', roadside_technician:'Roadside Technician', requester:'Locksmith', approver:'Approver', manager:'Manager', admin:'Admin', owner:'Owner' };
  return m[r] || r;
}
// Returns a user's custom job title if set, otherwise falls back to their role label.
function userTitle(u){ if (u && u.title && String(u.title).trim()) return String(u.title).trim(); if (u && u.isOwner) return 'Owner'; return roleLabel(u && u.role); }
// Owner is treated as admin everywhere in the UI; isOwner is kept for labels.
function normalizeUserRole(u){ if (u && u.role === 'owner') { u.isOwner = true; u.role = 'admin'; } return u; }
function can(perm) {
  if (!state.user) return false;
  if (state.user.role === 'admin') return true;
  if (state.user.extra_perms && state.user.extra_perms.indexOf(perm) !== -1) return true;
  var cfg = state.permissions;
  var role = state.user.role;
  if (cfg && Object.prototype.toString.call(cfg[role]) === '[object Array]') return cfg[role].indexOf(perm) !== -1;
  return (PERM_DEFAULTS[role] || []).indexOf(perm) !== -1;
}

// Royalty access is OWNER-gated + an explicit per-person allowlist (users.extra_perms),
// deliberately NOT role-based — so admins are excluded unless an owner adds them.
function canRoyalty(level) {
  if (!state.user) return false;
  if (state.user.isOwner) return true;
  var ep = state.user.extra_perms || [];
  if (level === 'manage') return ep.indexOf('manage_royalty') !== -1;
  return ep.indexOf('view_royalty') !== -1 || ep.indexOf('manage_royalty') !== -1;
}

function urlB64ToUint8Array(base64String){
  var padding='='.repeat((4 - base64String.length % 4) % 4);
  var base64=(base64String + padding).replace(/-/g,'+').replace(/_/g,'/');
  var raw=atob(base64); var out=new Uint8Array(raw.length);
  for (var i=0;i<raw.length;i++) out[i]=raw.charCodeAt(i);
  return out;
}
async function pushRefreshBtn(){
  var btn=document.getElementById('push-btn'); if(!btn) return;
  var bell='<svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="vertical-align:-2px"><path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg> ';
  if(!('serviceWorker' in navigator)||!('PushManager' in window)||!('Notification' in window)){ btn.style.display='none'; return; }
  try{
    var reg=await navigator.serviceWorker.ready;
    var sub=await reg.pushManager.getSubscription();
    btn.innerHTML=bell+(sub?'Notifications on':'Enable notifications');
  }catch(e){ btn.innerHTML=bell+'Enable notifications'; }
}
async function pushToggle(){
  if(!('serviceWorker' in navigator)||!('PushManager' in window)||!('Notification' in window)){ novaAlert('This browser does not support notifications.'); return; }
  try{
    var reg=await navigator.serviceWorker.ready;
    var sub=await reg.pushManager.getSubscription();
    if(sub){
      try{ await api('POST','/push/unsubscribe',{endpoint:sub.endpoint}); }catch(e){}
      await sub.unsubscribe(); pushRefreshBtn(); return;
    }
    var perm=await Notification.requestPermission();
    if(perm!=='granted'){ novaAlert('Notifications were not enabled. You can turn them on in your browser site settings.'); return; }
    var keyResp=await api('GET','/push/key');
    if(!keyResp||!keyResp.key){ novaAlert('Notifications are not set up on the server yet.'); return; }
    var newSub=await reg.pushManager.subscribe({ userVisibleOnly:true, applicationServerKey:urlB64ToUint8Array(keyResp.key) });
    await api('POST','/push/subscribe',{ subscription:newSub.toJSON() });
    pushRefreshBtn();
  }catch(e){ novaAlert('Could not enable notifications: '+(e&&e.message?e.message:e)); }
}
