  var cityOpts = '<option value="">All cities</option>' + ((_inspCities || []).map(function (c) {
    return '<option value="' + escHtml(c.code) + '"' + (d._city === c.code ? ' selected' : '') + '>' + escHtml(c.name) + ' (' + escHtml(c.code) + ')</option>';
  }).join(''));
