    const f = results[0];
    const settings = results[1];
    function esc(s) { return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;'); }

    const compName = esc(settings.company_name || 'Lock And Roll, LLC');
